Implement the following feature in the code below: bpf: fix end-of-list detection in cgroup_storage_get_next_key().

Feature description:
list_next_entry() never returns NULL -- when the current element is the
last entry it wraps to the list head via container_of(). The subsequent
NULL check is therefore dead code and get_next_key() never returns
-ENOENT for the last element, instead reading storage->key from a bogus
pointer that aliases internal map fields and copying the result to
userspace.

Replace it with list_entry_is_head() so the function correctly returns
-ENOENT when there are no more entries.

Output the complete corrected function(s).

```c
static int cgroup_storage_get_next_key(struct bpf_map *_map, void *key,
			       void *_next_key)
{
struct bpf_cgroup_storage_map *map = map_to_storage(_map);
struct bpf_cgroup_storage *storage;

spin_lock_bh(&map->lock);

if (list_empty(&map->list))
	goto enoent;

if (key) {
	storage = cgroup_storage_lookup(map, key, true);
	if (!storage)
		goto enoent;

	storage = list_next_entry(storage, list_map);
	if (!storage)
		goto enoent;
} else {
	storage = list_first_entry(&map->list,
				 struct bpf_cgroup_storage, list_map);
}

spin_unlock_bh(&map->lock);

if (attach_type_isolated(&map->map)) {
	struct bpf_cgroup_storage_key *next = _next_key;
	*next = storage->key;
} else {
	__u64 *next = _next_key;
	*next = storage->key.cgroup_inode_id;
}
return 0;

enoent:
spin_unlock_bh(&map->lock);
return -ENOENT;
}
```

```c
static int cgroup_storage_get_next_key(struct bpf_map *_map, void *key,
			       void *_next_key)
{
struct bpf_cgroup_storage_map *map = map_to_storage(_map);
struct bpf_cgroup_storage *storage;

spin_lock_bh(&map->lock);

if (list_empty(&map->list))
	goto enoent;

if (key) {
	storage = cgroup_storage_lookup(map, key, true);
	if (!storage)
		goto enoent;

	storage = list_next_entry(storage, list_map);
	if (list_entry_is_head(storage, &map->list, list_map))
		goto enoent;
} else {
	storage = list_first_entry(&map->list,
				 struct bpf_cgroup_storage, list_map);
}

spin_unlock_bh(&map->lock);

if (attach_type_isolated(&map->map)) {
	struct bpf_cgroup_storage_key *next = _next_key;
	*next = storage->key;
} else {
	__u64 *next = _next_key;
	*next = storage->key.cgroup_inode_id;
}
return 0;

enoent:
spin_unlock_bh(&map->lock);
return -ENOENT;
}
```

Fix the following bug in the code below: 9p: fix memory leak in v9fs_init_fs_context error path.

Problem description:
Move the assignments of fc->ops and fc->fs_private to right after the
kzalloc, before any fallible operations. Previously these were assigned
at the end of the function, after the kstrdup calls for uname and aname.
If either kstrdup failed, the error path would set fc->need_free but
leave fc->ops NULL, so put_fs_context() would never call v9fs_free_fc()
to free the allocated context and any already-duplicated strings.

Assisted-by: Claude:claude-opus-4-6
Message-ID: <20260225135745.351984-1-sashal@kernel.org>

Output the complete corrected function(s).

```c
static int v9fs_init_fs_context(struct fs_context *fc)
{
struct v9fs_context	*ctx;

ctx = kzalloc_obj(*ctx);
if (!ctx)
	return -ENOMEM;

/* initialize core options */
ctx->session_opts.afid = ~0;
ctx->session_opts.cache = CACHE_NONE;
ctx->session_opts.session_lock_timeout = P9_LOCK_TIMEOUT;
ctx->session_opts.uname = kstrdup(V9FS_DEFUSER, GFP_KERNEL);
if (!ctx->session_opts.uname)
	goto error;

ctx->session_opts.aname = kstrdup(V9FS_DEFANAME, GFP_KERNEL);
if (!ctx->session_opts.aname)
	goto error;

ctx->session_opts.uid = INVALID_UID;
ctx->session_opts.dfltuid = V9FS_DEFUID;
ctx->session_opts.dfltgid = V9FS_DEFGID;

/* initialize client options */
ctx->client_opts.proto_version = p9_proto_2000L;
ctx->client_opts.msize = DEFAULT_MSIZE;

/* initialize fd transport options */
ctx->fd_opts.port = P9_FD_PORT;
ctx->fd_opts.rfd = ~0;
ctx->fd_opts.wfd = ~0;
ctx->fd_opts.privport = false;

/* initialize rdma transport options */
ctx->rdma_opts.port = P9_RDMA_PORT;
ctx->rdma_opts.sq_depth = P9_RDMA_SQ_DEPTH;
ctx->rdma_opts.rq_depth = P9_RDMA_RQ_DEPTH;
ctx->rdma_opts.timeout = P9_RDMA_TIMEOUT;
ctx->rdma_opts.privport = false;

fc->ops = &v9fs_context_ops;
fc->fs_private = ctx;

return 0;
error:
fc->need_free = 1;
return -ENOMEM;
}
```

