Fix the following bug in the code below: selinux: fix avdcache auditing.

Problem description:
The per-task avdcache was incorrectly saving and reusing the
audited vector computed by avc_audit_required() rather than
recomputing based on the currently requested permissions and
distinguishing the denied versus allowed cases. As a result,
some permission checks were not being audited, e.g.
directory write checks after a previously cached directory
search check.

[PM: line wrap tweaks]

Output the complete corrected function(s).

```c
/**
* selinux_inode_permission - Check if the current task can access an inode
* @inode: the inode that is being accessed
* @requested: the accesses being requested
*
* Check if the current task is allowed to access @inode according to
* @requested.  Returns 0 if allowed, negative values otherwise.
*/
static int selinux_inode_permission(struct inode *inode, int requested)
{
       int mask;
       u32 perms;
       u32 sid = current_sid();
       struct task_security_struct *tsec;
       struct inode_security_struct *isec;
       struct avdc_entry *avdc;
       int rc, rc2;
       u32 audited, denied;

       mask = requested & (MAY_READ|MAY_WRITE|MAY_EXEC|MAY_APPEND);

       /* No permission to check.  Existence test. */
       if (!mask)
	       return 0;

       tsec = selinux_task(current);
       if (task_avdcache_permnoaudit(tsec, sid))
	       return 0;

       isec = inode_security_rcu(inode, requested & MAY_NOT_BLOCK);
       if (IS_ERR(isec))
	       return PTR_ERR(isec);
       perms = file_mask_to_av(inode->i_mode, mask);

       rc = task_avdcache_search(tsec, isec, &avdc);
       if (likely(!rc)) {
	       /* Cache hit. */
	       audited = perms & avdc->audited;
	       denied = perms & ~avdc->allowed;
	       if (unlikely(denied && enforcing_enabled() &&
			    !avdc->permissive))
		       rc = -EACCES;
       } else {
	       struct av_decision avd;

	       /* Cache miss. */
	       rc = avc_has_perm_noaudit(sid, isec->sid, isec->sclass,
					 perms, 0, &avd);
	       audited = avc_audit_required(perms, &avd, rc,
		       (requested & MAY_ACCESS) ? FILE__AUDIT_ACCESS : 0,
		       &denied);
	       task_avdcache_update(tsec, isec, &avd, audited);
       }

       if (likely(!audited))
	       return rc;

       rc2 = audit_inode_permission(inode, perms, audited, denied, rc);
       if (rc2)
	       return rc2;

       return rc;
}
```

