Refactor the following code: net: psp: check for device unregister when creating assoc.

Refactor strategy: add unlock

Refactoring description:
psp_assoc_device_get_locked() obtains a psp_dev reference via
psp_dev_get_for_sock() (which uses psp_dev_tryget() under RCU);
it then acquires psd->lock and drops the reference. Before
the lock is taken, psp_dev_unregister() can run to completion:
take psd->lock, clear out state, unlock, drop the registration
reference.

The expectation is that the lock prevents device unregistration,
but much like with netdevs special care has to be taken when
"upgrading" a reference to a locked device. Add the missing
check if device is still alive. psp_dev_is_registered() exists
already but had no callers, which makes me wonder if I either
forgot to add this or lost the check during refactoring...

Output the complete corrected function(s).

```c
/* Key etc. */

int psp_assoc_device_get_locked(const struct genl_split_ops *ops,
			struct sk_buff *skb, struct genl_info *info)
{
struct socket *socket;
struct psp_dev *psd;
struct nlattr *id;
int fd, err;

if (GENL_REQ_ATTR_CHECK(info, PSP_A_ASSOC_SOCK_FD))
	return -EINVAL;

fd = nla_get_u32(info->attrs[PSP_A_ASSOC_SOCK_FD]);
socket = sockfd_lookup(fd, &err);
if (!socket)
	return err;

if (!sk_is_tcp(socket->sk)) {
	NL_SET_ERR_MSG_ATTR(info->extack,
			    info->attrs[PSP_A_ASSOC_SOCK_FD],
			    "Unsupported socket family and type");
	err = -EOPNOTSUPP;
	goto err_sock_put;
}

psd = psp_dev_get_for_sock(socket->sk);
if (psd) {
	err = psp_dev_check_access(psd, genl_info_net(info));
	if (err) {
		psp_dev_put(psd);
		psd = NULL;
	}
}

if (!psd && GENL_REQ_ATTR_CHECK(info, PSP_A_ASSOC_DEV_ID)) {
	err = -EINVAL;
	goto err_sock_put;
}

id = info->attrs[PSP_A_ASSOC_DEV_ID];
if (psd) {
	mutex_lock(&psd->lock);
	if (id && psd->id != nla_get_u32(id)) {
		mutex_unlock(&psd->lock);
		NL_SET_ERR_MSG_ATTR(info->extack, id,
				    "Device id vs socket mismatch");
		err = -EINVAL;
		goto err_psd_put;
	}

	psp_dev_put(psd);
} else {
	psd = psp_device_get_and_lock(genl_info_net(info), id);
	if (IS_ERR(psd)) {
		err = PTR_ERR(psd);
		goto err_sock_put;
	}
}

info->user_ptr[0] = psd;
info->user_ptr[1] = socket;

return 0;

err_psd_put:
psp_dev_put(psd);
err_sock_put:
sockfd_put(socket);
return err;
}
```

