Fix the following bug in the code below: KVM: s390: Fix lpsw/e breaking event handling.

Problem description:
LPSW and LPSWE need to set the gbea on completion but currently don't.
Time to fix this up.

LPSWEY was designed to not set the bear.

Output the complete corrected function(s).

```c
int kvm_s390_handle_lpsw(struct kvm_vcpu *vcpu)
{
psw_t *gpsw = &vcpu->arch.sie_block->gpsw;
psw32_t new_psw;
u64 addr;
int rc;
u8 ar;

vcpu->stat.instruction_lpsw++;

if (gpsw->mask & PSW_MASK_PSTATE)
	return kvm_s390_inject_program_int(vcpu, PGM_PRIVILEGED_OP);

addr = kvm_s390_get_base_disp_s(vcpu, &ar);
if (addr & 7)
	return kvm_s390_inject_program_int(vcpu, PGM_SPECIFICATION);

rc = read_guest(vcpu, addr, ar, &new_psw, sizeof(new_psw));
if (rc)
	return kvm_s390_inject_prog_cond(vcpu, rc);
if (!(new_psw.mask & PSW32_MASK_BASE))
	return kvm_s390_inject_program_int(vcpu, PGM_SPECIFICATION);
gpsw->mask = (new_psw.mask & ~PSW32_MASK_BASE) << 32;
gpsw->mask |= new_psw.addr & PSW32_ADDR_AMODE;
gpsw->addr = new_psw.addr & ~PSW32_ADDR_AMODE;
if (!is_valid_psw(gpsw))
	return kvm_s390_inject_program_int(vcpu, PGM_SPECIFICATION);
return 0;
}
```

```c
int kvm_s390_handle_lpsw(struct kvm_vcpu *vcpu)
{
psw_t *gpsw = &vcpu->arch.sie_block->gpsw;
psw32_t new_psw;
u64 addr, iaddr;
int rc;
u8 ar;

vcpu->stat.instruction_lpsw++;

iaddr = gpsw->addr - kvm_s390_get_ilen(vcpu);
if (gpsw->mask & PSW_MASK_PSTATE)
	return kvm_s390_inject_program_int(vcpu, PGM_PRIVILEGED_OP);

addr = kvm_s390_get_base_disp_s(vcpu, &ar);
if (addr & 7)
	return kvm_s390_inject_program_int(vcpu, PGM_SPECIFICATION);

rc = read_guest(vcpu, addr, ar, &new_psw, sizeof(new_psw));
if (rc)
	return kvm_s390_inject_prog_cond(vcpu, rc);
if (!(new_psw.mask & PSW32_MASK_BASE))
	return kvm_s390_inject_program_int(vcpu, PGM_SPECIFICATION);
gpsw->mask = (new_psw.mask & ~PSW32_MASK_BASE) << 32;
gpsw->mask |= new_psw.addr & PSW32_ADDR_AMODE;
gpsw->addr = new_psw.addr & ~PSW32_ADDR_AMODE;
if (!is_valid_psw(gpsw))
	return kvm_s390_inject_program_int(vcpu, PGM_SPECIFICATION);
vcpu->arch.sie_block->gbea = iaddr;
return 0;
}
