Fix the following bug in the code below: usb: gadget: renesas_usb3: validate endpoint index in standard request handlers.

Problem description:
The GET_STATUS and SET/CLEAR_FEATURE handlers extract the endpoint
number from the host-supplied wIndex without any sort of validation.
Fix this up by validating the number of endpoints actually match up with
the number the device has before attempting to dereference a pointer
based on this math.

This is just like what was done in commit ee0d382feb44 ("usb: gadget:
aspeed_udc: validate endpoint index for ast udc") for the aspeed driver.

Assisted-by: gregkh_clanker_t1000

Output the complete corrected function(s).

```c
static bool usb3_std_req_get_status(struct renesas_usb3 *usb3,
			    struct usb_ctrlrequest *ctrl)
{
bool stall = false;
struct renesas_usb3_ep *usb3_ep;
int num;
u16 status = 0;
__le16 tx_data;

switch (ctrl->bRequestType & USB_RECIP_MASK) {
case USB_RECIP_DEVICE:
	if (usb3->gadget.is_selfpowered)
		status |= 1 << USB_DEVICE_SELF_POWERED;
	if (usb3->gadget.speed == USB_SPEED_SUPER)
		status |= usb3_feature_get_un_enabled(usb3);
	break;
case USB_RECIP_INTERFACE:
	break;
case USB_RECIP_ENDPOINT:
	num = le16_to_cpu(ctrl->wIndex) & USB_ENDPOINT_NUMBER_MASK;
	usb3_ep = usb3_get_ep(usb3, num);
	if (usb3_ep->halt)
		status |= 1 << USB_ENDPOINT_HALT;
	break;
default:
	stall = true;
	break;
}

if (!stall) {
	tx_data = cpu_to_le16(status);
	dev_dbg(usb3_to_dev(usb3), "get_status: req = %p\n",
		usb_req_to_usb3_req(usb3->ep0_req));
	usb3_pipe0_internal_xfer(usb3, &tx_data, sizeof(tx_data),
				 usb3_pipe0_get_status_completion);
}

return stall;
}
