	       ret = recv(fd, buf + nread, len - nread, flags);
	       timeout_check("recv");

	       if (ret < 0 && errno == EINTR)
		       continue;
	       if (ret <= 0)
		       break;

	       if (flags & MSG_PEEK) {
		       if (ret >= expected_ret) {
			       nread = ret;
			       break;
		       }
		       timeout_usleep(RECV_PEEK_RETRY_USEC);
		       continue;
	       }

	       nread += ret;
