       timeout_end();

       if (expected_ret < 0) {
	       if (ret != -1) {
		       fprintf(stderr, "bogus recv(2) return value %zd (expected %zd)\n",
			       ret, expected_ret);
		       exit(EXIT_FAILURE);
	       }
	       if (errno != -expected_ret) {
		       perror("recv");
		       exit(EXIT_FAILURE);
	       }
	       return;
       }

       if (ret < 0) {
	       perror("recv");
	       exit(EXIT_FAILURE);
       }

       if (nread != expected_ret) {
	       if (ret == 0)
		       fprintf(stderr, "unexpected EOF while receiving bytes\n");

