			continue;
		}

		pcu->have_dle = false;
		pcu->read_buf[pcu->read_pos++] = data;
		pcu->check_sum += data;
		continue;
	}

	switch (data) {
	case IMS_PCU_PROTOCOL_STX:
		if (pcu->have_stx)
			dev_warn(pcu->dev,
				 "Unexpected STX at byte %d, discarding old data\n",
				 pcu->read_pos);
		ims_pcu_reset_packet(pcu);
		pcu->have_stx = true;
		break;

	case IMS_PCU_PROTOCOL_DLE:
		pcu->have_dle = true;
		break;

	case IMS_PCU_PROTOCOL_ETX:
		if (pcu->read_pos < IMS_PCU_MIN_PACKET_LEN) {
			dev_warn(pcu->dev,
				 "Short packet received (%d bytes), ignoring\n",
				 pcu->read_pos);
		} else if (pcu->check_sum != 0) {
			dev_warn(pcu->dev,
				 "Invalid checksum in packet (%d bytes), ignoring\n",
				 pcu->read_pos);
		} else {
			ims_pcu_handle_response(pcu);
		}

		ims_pcu_reset_packet(pcu);
		break;

	default:
		if (pcu->read_pos >= IMS_PCU_BUF_SIZE) {
			dev_warn(pcu->dev,
				 "Packet too long (%d bytes), discarding\n",
				 pcu->read_pos);
			ims_pcu_reset_packet(pcu);
			continue;
		}

		pcu->read_buf[pcu->read_pos++] = data;
		pcu->check_sum += data;
		break;
	}
}
}
