Fix the following bug in the code below: sched_ext: Drop spurious warning on kick during scheduler disable.

Problem description:
kick_cpus_irq_workfn() warns when scx_kick_syncs is NULL, but this can
legitimately happen when a BPF timer or other kick source races with
free_kick_syncs() during scheduler disable. Drop the pr_warn_once() and
add a comment explaining the race.

Output the complete corrected function(s).

```c
static void kick_cpus_irq_workfn(struct irq_work *irq_work)
{
struct rq *this_rq = this_rq();
struct scx_rq *this_scx = &this_rq->scx;
struct scx_kick_syncs __rcu *ksyncs_pcpu = __this_cpu_read(scx_kick_syncs);
bool should_wait = false;
unsigned long *ksyncs;
s32 cpu;

if (unlikely(!ksyncs_pcpu)) {
	pr_warn_once("kick_cpus_irq_workfn() called with NULL scx_kick_syncs");
	return;
}

ksyncs = rcu_dereference_bh(ksyncs_pcpu)->syncs;

for_each_cpu(cpu, this_scx->cpus_to_kick) {
	should_wait |= kick_one_cpu(cpu, this_rq, ksyncs);
	cpumask_clear_cpu(cpu, this_scx->cpus_to_kick);
	cpumask_clear_cpu(cpu, this_scx->cpus_to_kick_if_idle);
}

for_each_cpu(cpu, this_scx->cpus_to_kick_if_idle) {
	kick_one_cpu_if_idle(cpu, this_rq);
	cpumask_clear_cpu(cpu, this_scx->cpus_to_kick_if_idle);
}

/*
 * Can't wait in hardirq — kick_sync can't advance, deadlocking if
 * CPUs wait for each other. Defer to kick_sync_wait_bal_cb().
 */
if (should_wait) {
	raw_spin_rq_lock(this_rq);
	this_scx->kick_sync_pending = true;
	resched_curr(this_rq);
	raw_spin_rq_unlock(this_rq);
}
}
```

